// If the CURRENT characters match, they can both extend a shared subsequence:
// s1[i-1] == s2[j-1]  ->  dp[i][j] = dp[i-1][j-1] + 1

// If they DON'T match, the best is whichever of the two smaller subproblems is longer:
// s1[i-1] != s2[j-1]  ->  dp[i][j] = max(dp[i-1][j], dp[i][j-1])

#include <iostream>
#include <vector>
#include <string>

using namespace std;

int longestCommonSubsequence(string s1, string s2)
{
    int n = s1.size();
    int m = s2.size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));

    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            if (s1[i - 1] == s2[j - 1])
            {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            }
            else
            {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
    }

    return dp[n][m];
}

int main()
{
    cout << longestCommonSubsequence("ABCDE", "ACE") << endl;

    return 0;
}

